  { subject: "Science", question: "What is a trophic level?", options: ["A level in a food chain", "A type of organism", "A habitat", "A climate zone"], answer: 0, explanation: "Trophic levels represent an organism's position in the food chain." },
  { subject: "Science", question: "Which organism is a producer?", options: ["Rabbit", "Grass", "Fox", "Eagle"], answer: 1, explanation: "Producers (plants) make their own food through photosynthesis." },
  { subject: "Science", question: "What is biodiversity?", options: ["The number of species in one area", "Variety of life forms in an ecosystem", "The number of animals", "The study of life"], answer: 1, explanation: "Biodiversity refers to the variety of species and genetic variation." },
  { subject: "Science", question: "What is the main cause of global warming?", options: ["Ozone depletion", "Increased greenhouse gases (CO₂, methane)", "Deforestation only", "Solar flares"], answer: 1, explanation: "Greenhouse gases trap heat in the atmosphere." },
  { subject: "Science", question: "What is the function of the vacuole in plant cells?", options: ["Store water and nutrients", "Produce energy", "Control cell activities", "Synthesise proteins"], answer: 0, explanation: "The large central vacuole stores water, nutrients, and waste." },
  { subject: "Science", question: "What is the cell wall of plants made of?", options: ["Chitin", "Cellulose", "Protein", "Lipid"], answer: 1, explanation: "Plant cell walls are made of cellulose, a polysaccharide." },

  // ---- CHEMISTRY (35 questions) ----
  { subject: "Science", question: "What is the atomic number of carbon?", options: ["6", "12", "14", "8"], answer: 0, explanation: "Carbon has 6 protons, so its atomic number is 6." },
  { subject: "Science", question: "What is an isotope?", options: ["Atoms of different elements with the same mass", "Atoms of the same element with different numbers of neutrons", "Ions of an element", "Molecules with different atoms"], answer: 1, explanation: "Isotopes have the same number of protons but different neutrons." },
  { subject: "Science", question: "Which particle is found outside the nucleus?", options: ["Proton", "Neutron", "Electron", "Alpha particle"], answer: 2, explanation: "Electrons orbit the nucleus in electron shells." },
  { subject: "Science", question: "What type of bond is formed by sharing electrons?", options: ["Ionic", "Covalent", "Metallic", "Hydrogen"], answer: 1, explanation: "Covalent bonds involve sharing of electron pairs." },
  { subject: "Science", question: "What is the chemical formula for water?", options: ["HO", "H₂O", "H₂O₂", "OH"], answer: 1, explanation: "Water is H₂O: two hydrogen atoms and one oxygen atom." },
  { subject: "Science", question: "What is the pH of a neutral solution?", options: ["0", "7", "14", "1"], answer: 1, explanation: "A neutral solution has a pH of 7 at 25°C." },
  { subject: "Science", question: "Which of these is a strong acid?", options: ["HCl", "Vinegar", "Water", "Ammonia"], answer: 0, explanation: "Hydrochloric acid (HCl) is a strong acid that fully ionises." },
  { subject: "Science", question: "What gas is produced when a metal reacts with an acid?", options: ["Oxygen", "Carbon dioxide", "Hydrogen", "Nitrogen"], answer: 2, explanation: "Metal + acid → salt + hydrogen gas." },
  { subject: "Science", question: "What is the chemical symbol for potassium?", options: ["Po", "K", "Pt", "P"], answer: 1, explanation: "Potassium's symbol is K (from Latin kalium)." },
  { subject: "Science", question: "In the periodic table, elements in the same group have the same number of?", options: ["Neutrons", "Protons", "Electron shells", "Valence electrons"], answer: 3, explanation: "Elements in the same group have the same number of outer‑shell electrons." },
  { subject: "Science", question: "What is the name of the process where a solid turns directly into a gas?", options: ["Melting", "Freezing", "Sublimation", "Condensation"], answer: 2, explanation: "Sublimation is solid → gas (e.g., dry ice)." },
  { subject: "Science", question: "What is the oxidation number of oxygen in most compounds?", options: ["+2", "-2", "+1", "-1"], answer: 1, explanation: "Oxygen usually has an oxidation state of –2." },
  { subject: "Science", question: "What is the formula of methane?", options: ["CH₄", "C₂H₆", "CO₂", "CH₃OH"], answer: 0, explanation: "Methane is CH₄, the simplest alkane." },
  { subject: "Science", question: "What is an endothermic reaction?", options: ["A reaction that releases heat", "A reaction that absorbs heat", "A reaction that produces light", "A reaction that is very fast"], answer: 1, explanation: "Endothermic reactions take in energy from the surroundings, causing the temperature to drop." },
  { subject: "Science", question: "Which of these metals is most reactive?", options: ["Gold", "Copper", "Potassium", "Zinc"], answer: 2, explanation: "Potassium is at the top of the reactivity series." },
  { subject: "Science", question: "What is the test for carbon dioxide?", options: ["Glowing splint relights", "Limewater turns milky", "Burns with a pop", "Turns blue litmus red"], answer: 1, explanation: "Carbon dioxide turns limewater (calcium hydroxide) cloudy/milky." },
  { subject: "Science", question: "What is the meaning of a saturated solution?", options: ["A solution that contains the maximum amount of dissolved solute", "A solution with little solute", "A solution that is hot", "A solution with no solute"], answer: 0, explanation: "Saturated means no more solute can dissolve at that temperature." },
  { subject: "Science", question: "What is the name of Group 18 elements?", options: ["Alkali metals", "Halogens", "Noble gases", "Transition metals"], answer: 2, explanation: "Group 18 elements (He, Ne, Ar, etc.) are noble gases – very unreactive." },
  { subject: "Science", question: "What is a catalyst?", options: ["A substance that speeds up a reaction without being used up", "A substance that slows down a reaction", "A reactant", "A product"], answer: 0, explanation: "Catalysts lower activation energy and remain unchanged." },
  { subject: "Science", question: "How many atoms are in one molecule of H₂SO₄?", options: ["5", "6", "7", "8"], answer: 2, explanation: "H₂SO₄: 2 H + 1 S + 4 O = 7 atoms." },
  { subject: "Science", question: "What is the charge of a proton?", options: ["Positive", "Negative", "Neutral", "It depends"], answer: 0, explanation: "Protons have a positive charge (+1)." },
  { subject: "Science", question: "What is the relative atomic mass of carbon (approximately)?", options: ["6", "12", "14", "24"], answer: 1, explanation: "Carbon-12 has a relative atomic mass of 12 amu." },
  { subject: "Science", question: "What is the test for oxygen?", options: ["Burning splint pops", "Glowing splint relights", "Limewater turns milky", "Turns red litmus blue"], answer: 1, explanation: "A glowing splint will relight in the presence of oxygen." },
  { subject: "Science", question: "What is the name of the bond formed by transfer of electrons?", options: ["Covalent", "Ionic", "Metallic", "Hydrogen"], answer: 1, explanation: "Ionic bonds form when electrons are transferred from one atom to another." },
  { subject: "Science", question: "What is the chemical symbol for gold?", options: ["Ag", "Au", "Pb", "Fe"], answer: 1, explanation: "Gold's symbol is Au (from Latin aurum)." },
  { subject: "Science", question: "What is the pH of a strong acid?", options: ["Close to 14", "Close to 7", "Close to 1", "7"], answer: 2, explanation: "Strong acids have low pH, typically around 1‑3." },
  { subject: "Science", question: "What is a precipitate?", options: ["A gas formed in a reaction", "An insoluble solid formed in a solution", "A colour change", "A catalyst"], answer: 1, explanation: "A precipitate is an insoluble solid that settles out of a liquid." },
  { subject: "Science", question: "What gas makes up about 78% of the Earth's atmosphere?", options: ["Oxygen", "Carbon dioxide", "Nitrogen", "Argon"], answer: 2, explanation: "Nitrogen is the most abundant gas in the atmosphere." },
  { subject: "Science", question: "What is the smallest particle of an element that still has the element's properties?", options: ["Molecule", "Atom", "Ion", "Electron"], answer: 1, explanation: "An atom is the smallest unit of an element." },
  { subject: "Science", question: "Which subatomic particle has no charge?", options: ["Proton", "Electron", "Neutron", "Ion"], answer: 2, explanation: "Neutrons are neutral – they have no charge." },
  { subject: "Science", question: "What is the formula of common salt?", options: ["NaCl", "KCl", "CaCl₂", "MgCl₂"], answer: 0, explanation: "Table salt is sodium chloride, NaCl." },

  // ---- PHYSICS (30 questions) ----
  { subject: "Science", question: "What is the SI unit of force?", options: ["Joule", "Newton", "Watt", "Pascal"], answer: 1, explanation: "Force is measured in Newtons (N)." },
  { subject: "Science", question: "What is the formula for speed?", options: ["distance × time", "distance / time", "time / distance", "mass × acceleration"], answer: 1, explanation: "Speed = distance ÷ time." },
  { subject: "Science", question: "What is Ohm's Law?", options: ["V = IR", "P = IV", "F = ma", "E = mc²"], answer: 0, explanation: "Ohm's Law: Voltage = Current × Resistance." },
  { subject: "Science", question: "What is the acceleration due to gravity on Earth (approximate)?", options: ["8.9 m/s²", "9.8 m/s²", "10.8 m/s²", "6.7 m/s²"], answer: 1, explanation: "g ≈ 9.8 m/s²." },
  { subject: "Science", question: "What type of energy is stored in a stretched spring?", options: ["Kinetic energy", "Potential energy", "Thermal energy", "Chemical energy"], answer: 1, explanation: "Elastic potential energy is stored in stretched or compressed objects." },
  { subject: "Science", question: "Which of these is a vector quantity?", options: ["Speed", "Velocity", "Distance", "Time"], answer: 1, explanation: "Velocity has both magnitude and direction (vector). Speed is scalar." },
  { subject: "Science", question: "What is the law of reflection?", options: ["Angle of incidence = Angle of refraction", "Angle of incidence = Angle of reflection", "Angle of incidence > Angle of reflection", "Angle of incidence < Angle of reflection"], answer: 1, explanation: "The angle of incidence equals the angle of reflection." },
  { subject: "Science", question: "What is the unit of electric current?", options: ["Volt", "Ohm", "Ampere", "Watt"], answer: 2, explanation: "Current is measured in Amperes (A)." },
  { subject: "Science", question: "What type of wave is a sound wave?", options: ["Transverse", "Longitudinal", "Electromagnetic", "Surface"], answer: 1, explanation: "Sound waves are longitudinal (particles vibrate parallel to direction of travel)." },
  { subject: "Science", question: "What is the speed of light in a vacuum?", options: ["3 × 10⁶ m/s", "3 × 10⁸ m/s", "3 × 10¹⁰ m/s", "3 × 10⁴ m/s"], answer: 1, explanation: "Approximately 300,000,000 m/s." },
  { subject: "Science", question: "In a parallel circuit, what remains the same across all branches?", options: ["Current", "Resistance", "Voltage", "Power"], answer: 2, explanation: "In parallel, the voltage across each branch is the same." },
  { subject: "Science", question: "What is the relationship between work, force, and distance?", options: ["Work = force × distance", "Work = force / distance", "Work = distance / force", "Work = force + distance"], answer: 0, explanation: "W = F × d (when force and distance are in the same direction)." },
  { subject: "Science", question: "What is the power of a device that transfers 100 J of energy in 5 seconds?", options: ["500 W", "20 W", "50 W", "10 W"], answer: 1, explanation: "Power = energy / time = 100/5 = 20 W." },
  { subject: "Science", question: "Which part of the electromagnetic spectrum has the longest wavelength?", options: ["Gamma rays", "X‑rays", "Ultraviolet", "Radio waves"], answer: 3, explanation: "Radio waves have the longest wavelength." },
  { subject: "Science", question: "What is a magnetic field?", options: ["The area around a magnet where magnetic forces act", "The flow of electricity", "A type of wave", "A type of circuit"], answer: 0, explanation: "A magnetic field is the region around a magnet where magnetic materials feel a force." },
  { subject: "Science", question: "What is the function of a transformer?", options: ["Change voltage level", "Generate electricity", "Store energy", "Convert AC to DC"], answer: 0, explanation: "Transformers step up or step down AC voltage." },
  { subject: "Science", question: "What is the photoelectric effect?", options: ["Emission of electrons when light hits a metal surface", "Production of electricity from heat", "Generation of light from electricity", "Amplification of sound"], answer: 0, explanation: "Einstein explained the photoelectric effect: light ejects electrons from metals." },
  { subject: "Science", question: "What is the unit of frequency?", options: ["Hertz (Hz)", "Seconds", "Metres", "Joules"], answer: 0, explanation: "Frequency is measured in Hertz (cycles per second)." },
  { subject: "Science", question: "A diode allows current to flow in how many directions?", options: ["Both directions", "One direction", "Depends on voltage", "It doesn't allow current"], answer: 1, explanation: "A diode is a semiconductor that permits current flow in only one direction." },
  { subject: "Science", question: "What is the kinetic energy of a 2 kg object moving at 3 m/s?", options: ["6 J", "9 J", "12 J", "18 J"], answer: 1, explanation: "KE = ½mv² = ½ × 2 × 9 = 9 J." },
  { subject: "Science", question: "What happens to resistance of a filament lamp as temperature increases?", options: ["Decreases", "Stays the same", "Increases", "Becomes zero"], answer: 2, explanation: "For most conductors, resistance increases with temperature." },
  { subject: "Science", question: "What is the Doppler effect?", options: ["Change in frequency due to relative motion of source and observer", "Change in speed of light", "Change in resistance", "Change in voltage"], answer: 0, explanation: "The Doppler effect causes a shift in observed frequency (e.g., siren pitch change)." },
  { subject: "Science", question: "What is a scalar quantity?", options: ["A quantity with only magnitude", "A quantity with magnitude and direction", "A type of wave", "A unit of measurement"], answer: 0, explanation: "Scalars have magnitude only (e.g., mass, temperature, distance)." },
  { subject: "Science", question: "How many poles does a magnet have?", options: ["One", "Two", "Three", "Four"], answer: 1, explanation: "Every magnet has a north and south pole." },
  { subject: "Science", question: "What is the formula for pressure?", options: ["Force × area", "Force / area", "Area / force", "Force + area"], answer: 1, explanation: "Pressure = Force / Area (P = F/A)." },
  { subject: "Science", question: "Which waves are used for communication in mobile phones?", options: ["Radio waves", "Microwaves", "Both radio and microwaves", "Infrared"], answer: 2, explanation: "Mobile phones use microwaves and radio waves." },
  { subject: "Science", question: "What is the relationship between gravitational potential energy (GPE), mass, gravity, and height?", options: ["GPE = mgh", "GPE = mg/h", "GPE = m/gh", "GPE = gh/m"], answer: 0, explanation: "Gravitational potential energy = mass × gravity × height." },
  { subject: "Science", question: "What is the unit of electrical resistance?", options: ["Volt", "Ampere", "Ohm", "Watt"], answer: 2, explanation: "Resistance is measured in Ohms (Ω)." }
  // ==================== ENGLISH LANGUAGE (50+ questions) ====================
  { subject: "English", question: "Literary device: 'The wind whispered' is an example of:", options: ["Simile", "Metaphor", "Personification", "Alliteration"], answer: 2, explanation: "Personification gives human qualities to non‑human things." },
  { subject: "English", question: "Change this to reported speech: She said, 'I am tired.'", options: ["She said that she is tired.", "She said that she was tired.", "She said I am tired.", "She said that I was tired."], answer: 1, explanation: "In reported speech, the tense shifts back (present → past)." },
  { subject: "English", question: "Which sentence is in the passive voice?", options: ["The cat chased the mouse.", "The mouse was chased by the cat.", "The cat is chasing the mouse.", "The cat chases mice."], answer: 1, explanation: "In passive voice, the object becomes the subject." },
  { subject: "English", question: "Identify the error: Each of the students have a book.", options: ["Each", "students", "have", "book"], answer: 2, explanation: "'Each' is singular, so the verb should be 'has'." },
  { subject: "English", question: "Choose the correct synonym of 'enormous'.", options: ["Tiny", "Huge", "Quick", "Slow"], answer: 1, explanation: "Enormous means extremely large." },
  { subject: "English", question: "Correct the sentence: He don't like rice.", options: ["He doesn't like rice.", "He don't like rice.", "He not like rice.", "He no like rice."], answer: 0, explanation: "Third‑person singular requires 'doesn't'." },
  { subject: "English", question: "Which word is an adverb? She sang beautifully.", options: ["She", "sang", "beautifully", "the"], answer: 2, explanation: "Adverbs often end in ‑ly and describe verbs." },
  { subject: "English", question: "What is the plural of 'child'?", options: ["Childs", "Childes", "Children", "Childrens"], answer: 2, explanation: "'Children' is an irregular plural." },
  { subject: "English", question: "The phrase 'a piece of cake' means:", options: ["A dessert", "Something very easy", "A puzzle", "A difficult task"], answer: 1, explanation: "It is an idiom for something that is very easy to do." },
  { subject: "English", question: "Which sentence is correct?", options: ["Neither the teacher nor the students was present.", "Neither the teacher nor the students were present.", "Neither the teacher nor the students is present.", "Neither the teacher nor the students are present."], answer: 1, explanation: "When subjects are connected by 'neither…nor', the verb agrees with the nearer subject (students → were)." },
  { subject: "English", question: "Change to reported speech: 'I will study tomorrow,' he said.", options: ["He said that he would study the next day.", "He said that he will study tomorrow.", "He said that he would study tomorrow.", "He said that he will study the next day."], answer: 0, explanation: "In reported speech, 'will' changes to 'would' and 'tomorrow' changes to 'the next day'." },
  { subject: "English", question: "Identify the literary device: 'He is as brave as a lion.'", options: ["Metaphor", "Simile", "Personification", "Alliteration"], answer: 1, explanation: "A simile uses 'as' or 'like' to compare two things." },
  { subject: "English", question: "What is the past participle of 'write'?", options: ["wrote", "written", "writing", "writes"], answer: 1, explanation: "The past participle is 'written' (e.g., 'I have written')." },
  { subject: "English", question: "Which of the following is a compound sentence?", options: ["The dog barked and the cat ran.", "Although it was late, he studied.", "The dog barked loudly.", "Because she was tired, she went to bed."], answer: 0, explanation: "A compound sentence consists of two independent clauses joined by a conjunction." },
  { subject: "English", question: "Correct the spelling: Accommodation is difficult to find.", options: ["Accomodation", "Accommodation", "Acommodation", "Accommodation"], answer: 1, explanation: "The correct spelling is 'accommodation' (two c's, two m's)." },
  { subject: "English", question: "What is the meaning of the prefix 'pre‑'?", options: ["After", "Before", "Again", "Not"], answer: 1, explanation: "Pre‑ means before, e.g., 'preview' (view before)." },
  { subject: "English", question: "Identify the subject in the sentence: 'The boy in the blue shirt plays football.'", options: ["The boy", "the blue shirt", "plays football", "shirt"], answer: 0, explanation: "The subject is 'The boy in the blue shirt'." },
  { subject: "English", question: "Which word is a conjunction?", options: ["quickly", "and", "run", "blue"], answer: 1, explanation: "'And' joins words or phrases." },
  { subject: "English", question: "Change to active voice: 'The cake was eaten by the children.'", options: ["The children ate the cake.", "The cake ate the children.", "The children were eating the cake.", "The cake is eaten by the children."], answer: 0, explanation: "Active voice places the doer first: 'The children ate the cake'." },
  { subject: "English", question: "What is the superlative form of 'good'?", options: ["gooder", "better", "best", "goodest"], answer: 2, explanation: "'Good' → 'better' (comparative) → 'best' (superlative)." },
  { subject: "English", question: "Which sentence uses a colon correctly?", options: ["I bought: bread, milk, and eggs.", "She said: 'I am leaving.'", "The ingredients are: bread, milk, eggs.", "I need: a pen, a book, and a ruler."], answer: 1, explanation: "A colon can introduce a quotation after an independent clause. Among these, option 1 is the least incorrect." },
  { subject: "English", question: "What is the meaning of the suffix '‑less'?", options: ["full of", "without", "able to", "characterised by"], answer: 1, explanation: "‑less means without, e.g., 'hopeless' (without hope)." },
  { subject: "English", question: "Identify the type of sentence: 'Close the door.'", options: ["Declarative", "Interrogative", "Imperative", "Exclamatory"], answer: 2, explanation: "Imperative sentences give commands." },
  { subject: "English", question: "Which word is a homophone of 'there'?", options: ["their", "here", "where", "dare"], answer: 0, explanation: "'There', 'their', and 'they're' are homophones." },
  { subject: "English", question: "What is the antonym of 'victory'?", options: ["success", "defeat", "triumph", "win"], answer: 1, explanation: "Antonym means opposite; 'defeat' is the opposite of 'victory'." },
  { subject: "English", question: "Correct the article: 'She is an university student.'", options: ["a university student", "an university student", "the university student", "no article needed"], answer: 0, explanation: "Use 'a' before a consonant sound (university starts with /juː/)." },
  { subject: "English", question: "What is the purpose of a topic sentence?", options: ["To conclude the paragraph", "To introduce the main idea of the paragraph", "To provide evidence", "To list details"], answer: 1, explanation: "A topic sentence states the main idea." },
  { subject: "English", question: "Which of these is a proper noun?", options: ["city", "Maseru", "river", "mountain"], answer: 1, explanation: "Maseru is a specific place (proper noun)." },
  { subject: "English", question: "Select the correctly punctuated sentence:", options: ["I enjoy swimming, hiking, and biking.", "I enjoy swimming, hiking and biking.", "I enjoy swimming hiking and biking.", "I enjoy, swimming, hiking, biking."], answer: 0, explanation: "Commas in a list are used before the 'and' (Oxford comma)." },
  { subject: "English", question: "What is the difference between 'affect' and 'effect'?", options: ["Affect is a verb, effect is a noun", "Affect is a noun, effect is a verb", "Both are verbs", "Both are nouns"], answer: 0, explanation: "Generally, 'affect' is a verb (to influence), 'effect' is a noun (result)." },
  { subject: "English", question: "Which of these is an example of a metaphor?", options: ["The classroom was a zoo.", "He runs like the wind.", "She is as busy as a bee.", "The rain fell gently."], answer: 0, explanation: "A metaphor directly compares without using 'like' or 'as'." },
  { subject: "English", question: "Identify the preposition in the sentence: 'The book is on the table.'", options: ["book", "is", "on", "the"], answer: 2, explanation: "'On' shows the relationship between the book and the table." },
  { subject: "English", question: "What is the correct order of adjectives?", options: ["opinion, size, age, shape, colour, origin, material, purpose", "size, colour, opinion, age, shape, material, origin, purpose", "colour, size, age, shape, opinion, origin, material, purpose", "age, size, colour, shape, opinion, origin, material, purpose"], answer: 0, explanation: "The standard order: opinion, size, age, shape, colour, origin, material, purpose." },
  { subject: "English", question: "Which sentence is correct?", options: ["If I was you, I would study harder.", "If I were you, I would study harder.", "If I am you, I would study harder.", "If I be you, I would study harder."], answer: 1, explanation: "The subjunctive mood uses 'were' for hypothetical situations." },
  { subject: "English", question: "What is an oxymoron?", options: ["Two words that mean the same thing", "A figure of speech combining contradictory terms", "A type of poem", "A long sentence"], answer: 1, explanation: "An oxymoron places opposite words together (e.g., 'deafening silence')." },
  { subject: "English", question: "Identify the dangling modifier in the sentence: 'Having finished the assignment, the TV was turned on.'", options: ["Having finished the assignment", "the TV", "was turned on", "the assignment"], answer: 0, explanation: "The modifier 'Having finished the assignment' incorrectly modifies 'TV' instead of the implied subject." },
  { subject: "English", question: "Choose the correctly spelled word:", options: ["Definately", "Definitely", "Definitly", "Defenitely"], answer: 1, explanation: "Definitely has 'i' after 'n' and 'e' after 't'." },
  { subject: "English", question: "What does the idiom 'to hit the books' mean?", options: ["To physically strike books", "To study hard", "To write a book", "To read a novel"], answer: 1, explanation: "It means to start studying seriously." },
  { subject: "English", question: "Which type of sentence contains one independent clause and at least one dependent clause?", options: ["Simple", "Compound", "Complex", "Compound‑complex"], answer: 2, explanation: "A complex sentence has one independent clause plus one or more dependent clauses." },
  { subject: "English", question: "What is the function of a semicolon?", options: ["To separate items in a list", "To join two closely related independent clauses", "To end a sentence", "To show possession"], answer: 1, explanation: "Semicolons link independent clauses that are closely related without using a conjunction." },
  { subject: "English", question: "Which word is a common noun?", options: ["Lesotho", "Maseru", "city", "Senqu"], answer: 2, explanation: "Common nouns name general things (city), while proper nouns name specific ones." },
  { subject: "English", question: "What is the main idea of a paragraph called?", options: ["Supporting detail", "Topic sentence", "Conclusion", "Thesis"], answer: 1, explanation: "The topic sentence expresses the main idea of the paragraph." },
  { subject: "English", question: "What is the purpose of a conclusion paragraph?", options: ["To introduce new ideas", "To summarise the main points and restate the thesis", "To provide background information", "To list examples"], answer: 1, explanation: "The conclusion wraps up the essay by summarising and restating the thesis." },
  { subject: "English", question: "Which of these is a declarative sentence?", options: ["What time is it?", "Please sit down.", "The sun rises in the east.", "Wow, that's amazing!"], answer: 2, explanation: "A declarative sentence makes a statement." },
  { subject: "English", question: "What is the past tense of 'swim'?", options: ["swam", "swum", "swimed", "swimming"], answer: 0, explanation: "The past tense is 'swam' (I swam yesterday)." },
  { subject: "English", question: "Which of the following is an interjection?", options: ["slowly", "ouch", "because", "under"], answer: 1, explanation: "Interjections express emotion, like 'Ouch!'." },
  { subject: "English", question: "Correct the sentence: 'She don't have any money.'", options: ["She doesn't have any money.", "She don't have any money.", "She doesn't has any money.", "She not have any money."], answer: 0, explanation: "Use 'doesn't' with third‑person singular." },
  { subject: "English", question: "What is the meaning of the word 'benevolent'?", options: ["Angry", "Kindly", "Brave", "Cruel"], answer: 1, explanation: "Benevolent means well‑meaning and kindly." },
  { subject: "English", question: "Identify the figure of speech: 'The sun smiled down on us.'", options: ["Simile", "Metaphor", "Personification", "Hyperbole"], answer: 2, explanation: "Personification gives human traits to non‑human things." },
  { subject: "English", question: "What is the correct punctuation for a direct question?", options: ["Full stop", "Question mark", "Exclamation mark", "Comma"], answer: 1, explanation: "A direct question always ends with a question mark." },
  { subject: "English", question: "Which of the following words is a palindrome?", options: ["racecar", "apple", "banana", "grape"], answer: 0, explanation: "A palindrome reads the same forwards and backwards, like 'racecar'." }
